/**
 * MedX borders theme token runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Border widths and styles for tables and alerts.
 */
const BORDERS_TOKENS = Object.freeze({
  primary: { value: "theme-borders-primary", scope: "theme" },
  secondary: { value: "theme-borders-secondary", scope: "theme" },
  muted: { value: "theme-borders-muted", scope: "theme" },
  accent: { value: "theme-borders-accent", scope: "theme" },
  surface: { value: "theme-borders-surface", scope: "theme" },
});

const BORDERS_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const BORDERS_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const bordersRegistry = new Map();
const BORDERS_listeners = new Set();
let BORDERS_seq = 0;

function createBordersId(prefix = "medx-theme-borders") {
  BORDERS_seq += 1;
  return `${prefix}-${BORDERS_seq}`;
}

function registerBorders(config = {}) {
  const entryId = config.id ?? createBordersId();
  const preset = BORDERS_PRESETS[config.preset ?? "default"] ?? BORDERS_PRESETS.default;
  const token = BORDERS_TOKENS[config.token ?? preset.token] ?? BORDERS_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: BORDERS_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  bordersRegistry.set(entryId, entry);
  notifyBordersListeners("register", entry);
  return entry;
}

function updateBorders(id, patch = {}) {
  const entry = bordersRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyBordersListeners("update", entry);
  return entry;
}

function resolveBorders(id) {
  const entry = bordersRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listBordersEntries(filter = {}) {
  let items = Array.from(bordersRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onBordersEvent(listener) {
  BORDERS_listeners.add(listener);
  return () => BORDERS_listeners.delete(listener);
}

function notifyBordersListeners(type, entry) {
  for (const listener of BORDERS_listeners) {
    try {
      listener({ type, entry, registrySize: bordersRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:theme:borders] listener error", err.message);
    }
  }
}

function getBordersMetrics() {
  const items = listBordersEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(BORDERS_TOKENS).length,
    presets: Object.keys(BORDERS_PRESETS).length,
  };
}

async function runMedxBorders() {
  console.log("[medx:ui:theme:borders] runtime initialized");
  console.log(`[medx:ui:theme:borders] tokens=${Object.keys(BORDERS_TOKENS).length} presets=${Object.keys(BORDERS_PRESETS).length}`);

  const events = [];
  onBordersEvent((e) => events.push(e.type));

  const domains = Object.keys(BORDERS_SUPPLY_CHAIN);
  const presets = Object.keys(BORDERS_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerBorders({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "theme/borders" },
    });
  }

  const first = listBordersEntries()[0];
  if (first) updateBorders(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getBordersMetrics();
  const resolved = first ? resolveBorders(first.id) : null;

  console.log(`[medx:ui:theme:borders] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:theme:borders] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:theme:borders] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:theme:borders] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:theme:borders] bootstrap complete");
}

module.exports = runMedxBorders;
